{"tool":"sql_query","args":{"query":"WITH thresholds AS (
  SELECT 1
), matches AS (
  SELECT rowid AS file_order, lot_id, plant_code, line_id, shift, build_date, battery_health_score_pct, warranty_risk_index, release_status
  FROM production_quality_measurements
  WHERE lower(release_status) <> lower('Released')
    AND CAST(battery_health_score_pct AS REAL) > 96
    AND CAST(warranty_risk_index AS REAL) < 2.0
), containment AS (
  SELECT * FROM matches WHERE lower(release_status)=lower('Containment') ORDER BY file_order ASC LIMIT 1
), hold AS (
  SELECT * FROM matches WHERE lower(release_status)=lower('Hold') ORDER BY file_order ASC LIMIT 1
)
SELECT (SELECT COUNT(*) FROM matches) AS non_released_passing_count,
       c.lot_id AS containment_lot_id, c.plant_code AS containment_plant_code, c.line_id AS containment_line_id, c.shift AS containment_shift, c.build_date AS containment_build_date, c.battery_health_score_pct AS containment_battery_health_score_pct, c.warranty_risk_index AS containment_warranty_risk_index, c.release_status AS containment_release_status,
       h.lot_id AS hold_lot_id, h.plant_code AS hold_plant_code, h.line_id AS hold_line_id, h.shift AS hold_shift, h.build_date AS hold_build_date, h.battery_health_score_pct AS hold_battery_health_score_pct, h.warranty_risk_index AS hold_warranty_risk_index, h.release_status AS hold_release_status
FROM containment c CROSS JOIN hold h","limit":5}}
{"answer":"Using main.md release thresholds battery_health_score_pct > 96 and warranty_risk_index < 2.0, there are 95 non-released lots (release_status not Released) that still pass. First Containment example in file order: lot_id LOT-0004, plant_code PLT-NORTH, line_id L04, shift B, build_date 2025-01-05, battery_health_score_pct 98.4, warranty_risk_index 1.8, release_status Containment. First Hold example in file order: lot_id LOT-0014, plant_code PLT-EAST, line_id L03, shift B, build_date 2025-01-15, battery_health_score_pct 97.8, warranty_risk_index 1.8, release_status Hold."}

